# Helper function to extract images from chat text
def extract_images(text):
    """Extract image filenames from chat text"""
    images = []
    pattern = r'<attached: (00\d+-[^>]+\.(?:jpg|png|jpeg))>'
    matches = re.findall(pattern, text)
    return [f"media/{img}" for img in matches]

